// PATCH: Cover --agent dry-runs suppressing the human stderr request preview.
func TestExecuteAgentDryRunKeepsStderrJSONClean(t *testing.T) {
	cfgPath := writeBaseURLConfig(t, "https://example.test")
	t.Setenv("LUNCHMONEY_API_KEY", "test-token")

	stdout, stderr, err := executeForTest(t, "--config", cfgPath, "categories", "create-category", "--name", "Probe", "--group-id", "75", "--agent", "--dry-run")
	if err != nil {
		t.Fatalf("Execute: %v", err)
	}
	if stderr != "" {
		t.Fatalf("stderr = %q, want no request preview under --agent", stderr)
	}
	if !json.Valid([]byte(stdout)) {
		t.Fatalf("stdout = %q, want JSON", stdout)
	}
	if strings.Contains(stdout, "POST https://") {
		t.Fatalf("stdout contains dry-run request preview: %q", stdout)
	}
	var env map[string]any
	if err := json.Unmarshal([]byte(stdout), &env); err != nil {
		t.Fatalf("unmarshal dry-run stdout: %v", err)
	}
	data, ok := env["data"].(map[string]any)
	if !ok {
		t.Fatalf("dry-run data = %#v, want object", env["data"])
	}
	if data["method"] != "POST" || data["path"] != "/categories" {
		t.Fatalf("dry-run request data = %#v", data)
	}
	if _, ok := data["request_body"].(map[string]any); !ok {
		t.Fatalf("dry-run request_body = %#v, want object", data["request_body"])
	}
}

// PATCH: Custom output-only commands must respect Cobra's writer for --deliver.
func TestAgentContextDeliverWritesFile(t *testing.T) {
	outPath := filepath.Join(t.TempDir(), "agent-context.json")
	stdout, stderr, err := executeForTest(t, "agent-context", "--deliver", "file:"+outPath)
	if err != nil {
		t.Fatalf("Execute: %v", err)
	}
	if stderr != "" {
		t.Fatalf("stderr = %q", stderr)
	}
	if !json.Valid([]byte(stdout)) {
		t.Fatalf("stdout = %q, want JSON", stdout)
	}
	data, err := os.ReadFile(outPath)
	if err != nil {
		t.Fatalf("read delivered file: %v", err)
	}
	if len(data) == 0 || !json.Valid(data) {
		t.Fatalf("delivered file = %q, want JSON content", string(data))
	}
}

// PATCH(env-trim): writes a temp config TOML with base_url set so tests can
// point the client at httptest servers without an env-var override.
func writeBaseURLConfig(t *testing.T, baseURL string) string {
	t.Helper()
	path := filepath.Join(t.TempDir(), "config.toml")
	body := fmt.Sprintf("base_url = %q\n", baseURL)
	if err := os.WriteFile(path, []byte(body), 0o600); err != nil {
		t.Fatalf("write test config: %v", err)
	}
	return path
}

func executeForTest(t *testing.T, args ...string) (string, string, error) {
	return executeForTestWithInput(t, "", args...)
}

func executeForTestWithInput(t *testing.T, stdin string, args ...string) (string, string, error) {
	t.Helper()

	oldArgs := os.Args
	oldStdin := os.Stdin
	oldStdout := os.Stdout
	oldStderr := os.Stderr
	inR, inW, err := os.Pipe()
	if err != nil {
		t.Fatalf("pipe stdin: %v", err)
	}
	if _, err := inW.WriteString(stdin); err != nil {
		t.Fatalf("write stdin: %v", err)
	}
	if err := inW.Close(); err != nil {
		t.Fatalf("close stdin writer: %v", err)
	}
	outR, outW, err := os.Pipe()
	if err != nil {
		t.Fatalf("pipe stdout: %v", err)
	}
	errR, errW, err := os.Pipe()
	if err != nil {
		t.Fatalf("pipe stderr: %v", err)
	}
	outDone := make(chan string)
	errDone := make(chan string)
	go func() {
		b, _ := io.ReadAll(outR)
		outDone <- string(b)
	}()
	go func() {
		b, _ := io.ReadAll(errR)
		errDone <- string(b)
	}()

	os.Args = append([]string{"lunch-money-pp-cli"}, args...)
	os.Stdin = inR
	os.Stdout = outW
	os.Stderr = errW
	execErr := Execute()

	_ = outW.Close()
	_ = errW.Close()
	stdout := <-outDone
	stderr := <-errDone
	os.Args = oldArgs
	os.Stdin = oldStdin
	os.Stdout = oldStdout
	os.Stderr = oldStderr
	_ = inR.Close()
	_ = outR.Close()
	_ = errR.Close()

	return stdout, stderr, execErr
}
